def reciprocal_rank_fusion(ranked_lists: list[list[str]], k: int = 60) -> list[str]:
    """Combine multiple ranked lists using Reciprocal Rank Fusion."""
    rrf_scores: dict[str, float] = {}
    # Track first-encounter order for stable tie-breaking
    encounter_order: dict[str, int] = {}
    counter = 0

    for ranked_list in ranked_lists:
        for rank_minus_1, doc_id in enumerate(ranked_list):
            rank = rank_minus_1 + 1  # 1-indexed
            rrf_scores[doc_id] = rrf_scores.get(doc_id, 0.0) + 1.0 / (k + rank)
            if doc_id not in encounter_order:
                encounter_order[doc_id] = counter
                counter += 1

    # Sort by RRF score descending, then by encounter order ascending for ties
    sorted_docs = sorted(
        rrf_scores.keys(),
        key=lambda doc: (-rrf_scores[doc], encounter_order[doc])
    )
    return sorted_docs
